#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        int result = (b > a + c) && (b % 2 == 1);
        printf("%d\n", result);
    }
    return 0;
}

